var gas = msg.payload.gas;
var threshold = msg.payload.threshold;

msg.payload = {
    mode: "STD",
    anomaly: gas > threshold,
    predicted_crossing: msg.payload.predicted_crossing
};

return msg;

// ======================================================
// LETTURA VALORI DAL PAYLOAD MQTT
// ======================================================

// valore di gas letto dal sensore MQ2 (inviato dal Bridge)
var gas = msg.payload.gas;

// soglia calcolata dal Bridge (media altri garage * k)
var threshold = msg.payload.threshold;



// ======================================================
// STORICO DEI VALORI GAS
// ======================================================

// recupera lo storico dei valori salvato nel context del nodo
// se il nodo è appena partito lo inizializza come array vuoto
var history = context.get("gas_history") || [];

// recupera la media mobile del ciclo precedente
// serve per calcolare la velocità di crescita del gas
var previousAvg = context.get("previous_avg");

// aggiunge il nuovo valore gas allo storico
history.push(gas);

// mantiene lo storico lungo al massimo 20 valori
// rimuovendo il valore più vecchio
if (history.length > 20) {
    history.shift();
}



// ======================================================
// NON CI SONO ABBASTANZA DATI PER CALCOLARE UN TREND
// ======================================================

// se abbiamo meno di 5 valori non possiamo ancora stimare
// l'andamento del gas
if (history.length < 5) {

    // salva lo storico aggiornato
    context.set("gas_history", history);

    // nessuna anomalia rilevata
    msg.payload.mode = "STD";
    msg.payload.anomaly = false;

    // nessuna previsione di superamento soglia
    msg.payload.predicted_crossing = false;

    return msg;
}



// ======================================================
// CALCOLO MEDIA MOBILE
// ======================================================

// calcola la media dei valori nello storico
// (moving average degli ultimi N valori)
var sum = 0;

for (var i = 0; i < history.length; i++) {
    sum += history[i];
}

var movingAvg = sum / history.length;



// ======================================================
// PRIMA ITERAZIONE DEL TREND
// ======================================================

// se non esiste una media precedente non possiamo
// ancora calcolare la velocità di crescita
if (previousAvg == null) {

    context.set("previous_avg", movingAvg);
    context.set("gas_history", history);

    msg.payload.mode = "STD";
    msg.payload.anomaly = false;
    msg.payload.predicted_crossing = false;

    return msg;
}



// ======================================================
// VELOCITÀ DI CRESCITA DEL GAS
// ======================================================

// differenza tra la media attuale e quella precedente
// se positiva significa che il gas sta aumentando
var growthRate = movingAvg - previousAvg;

// aggiorna i valori salvati nel context per il prossimo ciclo
context.set("previous_avg", movingAvg);
context.set("gas_history", history);



// ======================================================
// PREDIZIONE DEL VALORE FUTURO
// ======================================================

// stima il valore del gas tra circa 30 secondi
// (150 cicli * 0.2 sec per ciclo)
var predictedGas = gas + (growthRate * 150);

// aggiunge al payload il valore predetto
msg.payload.predicted_gas = Math.round(predictedGas);



// ======================================================
// DECISIONE ANOMALIA
// ======================================================

// se il valore previsto supera la soglia
// segnaliamo al Bridge che si verificherà una condizione di anomalia
if (predictedGas > threshold) {

    msg.payload.mode = "STD";
    msg.payload.anomaly = true;

    // indica che la soglia verrà superata nel futuro
    msg.payload.predicted_crossing = true;

} else {

    msg.payload.mode = "STD";
    msg.payload.anomaly = false;

    msg.payload.predicted_crossing = false;
}



// ======================================================
// PAYLOAD INVIATO AL BRIDGE
// ======================================================
//
// Il messaggio JSON inviato al Bridge contiene:
//
// mode               → modalità operativa (STD = decisione automatica)
// anomaly            → True/False → indica se la ventola deve accendersi
// predicted_crossing → True/False → indica se il gas supererà la soglia
// predicted_gas      → valore stimato del gas tra ~30 secondi
//
// esempio payload finale:
//
// {
//   "mode": "STD",
//   "anomaly": false,
//   "predicted_crossing": true,
//   "predicted_gas": 245
// }
//
// Il Bridge utilizza:
// anomaly OR predicted_crossing
//
// per decidere se accendere la ventola.

return msg;
